<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Sorting Visualizer</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body {
    background: #0f0f13;
    color: #e0e0e0;
    font-family: system-ui, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    min-height: 100vh;
    padding: 24px;
    gap: 24px;
  }
  h1 { font-size: 1.4rem; color: #a78bfa; letter-spacing: 0.05em; }
  #bars {
    width: 100%;
    max-width: 800px;
    height: 320px;
    background: #1a1a24;
    border: 1px solid #2a2a3a;
    border-radius: 8px;
    display: flex;
    align-items: flex-end;
    gap: 2px;
    padding: 8px;
  }
  .bar {
    flex: 1;
    border-radius: 2px 2px 0 0;
    background: #7c3aed;
    transition: height 0.05s ease;
    min-width: 2px;
  }
  .bar.comparing { background: #f59e0b; }
  .bar.sorted-bar { background: #10b981; }
  .controls {
    display: flex;
    gap: 12px;
    flex-wrap: wrap;
    justify-content: center;
  }
  button {
    padding: 10px 28px;
    border: none;
    border-radius: 6px;
    font-size: 0.95rem;
    cursor: pointer;
    font-weight: 600;
    transition: opacity 0.15s;
  }
  button:hover { opacity: 0.85; }
  button:disabled { opacity: 0.4; cursor: not-allowed; }
  #sort { background: #7c3aed; color: #fff; }
  #shuffle { background: #0ea5e9; color: #fff; }
  #reset { background: #374151; color: #e0e0e0; }
  #status {
    font-size: 0.85rem;
    color: #6b7280;
    height: 1.2em;
  }
  .speed-row {
    display: flex;
    align-items: center;
    gap: 10px;
    font-size: 0.85rem;
    color: #9ca3af;
  }
  input[type=range] { accent-color: #7c3aed; }
</style>
</head>
<body>
<h1>Sorting Algorithm Visualizer</h1>
<div id="bars"></div>
<div class="controls">
  <button id="sort">Sort</button>
  <button id="shuffle">Shuffle</button>
  <button id="reset">Reset</button>
</div>
<div class="speed-row">
  <label for="speed">Speed:</label>
  <input type="range" id="speed" min="1" max="10" value="5">
  <span id="speed-label">5</span>
</div>
<div id="status"></div>

<script>
(function () {
  const DEFAULT_SIZE = 40;
  const barsEl = document.getElementById('bars');
  const statusEl = document.getElementById('status');
  const speedEl = document.getElementById('speed');
  const speedLabel = document.getElementById('speed-label');

  let arr = [];
  let animationId = null;

  // Insertion sort state
  let sortState = null;

  function initSortState(a) {
    return {
      arr: a,
      i: 1,
      j: 1,
      key: a[1],
      phase: 'start', // 'start' | 'shift' | 'done'
      comparing: [],
    };
  }

  function makeSortState() {
    sortState = initSortState(arr);
  }

  function defaultArray(n) {
    const a = [];
    for (let i = 0; i < n; i++) a.push(Math.round((i + 1) * (100 / n)));
    return a;
  }

  function shuffleArray(a) {
    const b = a.slice();
    for (let i = b.length - 1; i > 0; i--) {
      const j = Math.floor(Math.random() * (i + 1));
      [b[i], b[j]] = [b[j], b[i]];
    }
    return b;
  }

  function renderBars(comparing = [], sortedIndices = []) {
    const max = Math.max(...arr, 1);
    barsEl.innerHTML = '';
    arr.forEach((v, i) => {
      const bar = document.createElement('div');
      bar.className = 'bar';
      bar.style.height = (v / max * 100) + '%';
      if (sortedIndices.includes(i)) bar.classList.add('sorted-bar');
      else if (comparing.includes(i)) bar.classList.add('comparing');
      barsEl.appendChild(bar);
    });
  }

  // Insertion sort step-by-step
  // Returns true when fully sorted
  function sortStep() {
    if (!sortState) makeSortState();
    const s = sortState;

    if (s.phase === 'done') return true;

    // If arr length <= 1, trivially sorted
    if (arr.length <= 1) {
      s.phase = 'done';
      return true;
    }

    if (s.i >= arr.length) {
      s.phase = 'done';
      s.comparing = [];
      renderBars([], Array.from({ length: arr.length }, (_, i) => i));
      return true;
    }

    // Current step: compare arr[s.j] vs arr[s.j-1]
    if (s.j > 0 && arr[s.j - 1] > s.key) {
      s.comparing = [s.j - 1, s.j];
      arr[s.j] = arr[s.j - 1];
      s.j--;
      renderBars(s.comparing);
      return false;
    } else {
      arr[s.j] = s.key;
      s.comparing = [];
      renderBars();

      s.i++;
      if (s.i < arr.length) {
        s.key = arr[s.i];
        s.j = s.i;
      }

      if (s.i >= arr.length) {
        s.phase = 'done';
        renderBars([], Array.from({ length: arr.length }, (_, i) => i));
        return true;
      }
      return false;
    }
  }

  function isSorted() {
    for (let i = 1; i < arr.length; i++) {
      if (arr[i] < arr[i - 1]) return false;
    }
    return true;
  }

  function stopAnimation() {
    if (animationId !== null) {
      clearTimeout(animationId);
      animationId = null;
    }
  }

  function getDelay() {
    const v = parseInt(speedEl.value, 10);
    // speed 1 = 300ms, speed 10 = 5ms
    return Math.round(305 - v * 30);
  }

  function animateSort() {
    stopAnimation();
    document.getElementById('sort').disabled = true;
    statusEl.textContent = 'Sorting…';

    function step() {
      const done = sortStep();
      if (done) {
        statusEl.textContent = 'Sorted!';
        document.getElementById('sort').disabled = false;
        animationId = null;
      } else {
        animationId = setTimeout(step, getDelay());
      }
    }
    step();
  }

  // Public API
  window.viz = {
    array() { return arr.slice(); },
    setArray(a) {
      stopAnimation();
      arr = a.slice();
      sortState = null;
      makeSortState();
      renderBars();
      statusEl.textContent = '';
      document.getElementById('sort').disabled = false;
    },
    sortStep() { return sortStep(); },
    sorted() { return isSorted(); },
  };

  // Controls
  document.getElementById('sort').addEventListener('click', () => {
    if (isSorted()) {
      statusEl.textContent = 'Already sorted!';
      return;
    }
    animateSort();
  });

  document.getElementById('shuffle').addEventListener('click', () => {
    stopAnimation();
    arr = shuffleArray(arr.length ? arr : defaultArray(DEFAULT_SIZE));
    sortState = null;
    makeSortState();
    renderBars();
    statusEl.textContent = '';
    document.getElementById('sort').disabled = false;
  });

  document.getElementById('reset').addEventListener('click', () => {
    stopAnimation();
    arr = defaultArray(DEFAULT_SIZE);
    sortState = null;
    makeSortState();
    renderBars();
    statusEl.textContent = '';
    document.getElementById('sort').disabled = false;
  });

  speedEl.addEventListener('input', () => {
    speedLabel.textContent = speedEl.value;
  });

  // Init
  arr = shuffleArray(defaultArray(DEFAULT_SIZE));
  makeSortState();
  renderBars();
})();
</script>
</body>
</html>
